'use client';

import React, { useState, useMemo } from 'react';
import Link from 'next/link';
import { motion } from 'framer-motion';
import { Search as SearchIcon } from 'lucide-react';
import { themes } from '@/data/themes';
import { contentItems } from '@/data/content';
import PageHeader from '@/components/layout/PageHeader';
import SearchInput from '@/components/ui/SearchInput';
import Card from '@/components/ui/Card';
import Badge from '@/components/ui/Badge';
import EmptyState from '@/components/ui/EmptyState';

const categories = [
  { id: 'all', label: 'Tous' },
  { id: 'fondements', label: 'Fondements' },
  { id: 'pratique', label: 'Pratique' },
  { id: 'spiritualite', label: 'Spiritualité' },
  { id: 'comportement', label: 'Comportement' },
];

const categoryMapping: Record<string, string[]> = {
  fondements: ['aqida', 'croyance', 'tawhid', 'iman'],
  pratique: ['fiqh', 'adoration', 'piliers', 'tahara', 'purification'],
  spiritualite: ['adhkar', 'duaa', 'quotidien', 'quran', 'tafsir', 'hadith', 'sciences', 'moustalah'],
  comportement: ['akhlaq', 'adab', 'comportement', 'sira', 'histoire'],
};

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { staggerChildren: 0.06 },
  },
};

const itemVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.4, ease: 'easeOut' } },
};

export default function ExplorePage() {
  const [search, setSearch] = useState('');
  const [activeCategory, setActiveCategory] = useState('all');

  const filteredThemes = useMemo(() => {
    return themes.filter((theme) => {
      const matchesSearch =
        !search ||
        theme.title.toLowerCase().includes(search.toLowerCase()) ||
        theme.description.toLowerCase().includes(search.toLowerCase()) ||
        theme.tags.some((t) => t.toLowerCase().includes(search.toLowerCase()));

      const matchesCategory =
        activeCategory === 'all' ||
        theme.tags.some((t) => categoryMapping[activeCategory]?.includes(t));

      return matchesSearch && matchesCategory;
    });
  }, [search, activeCategory]);

  return (
    <div className="pb-nav space-y-6 py-4 sm:py-6">
      <PageHeader title="Explorer" subtitle="Parcourez les thèmes du savoir" />

      {/* Search */}
      <SearchInput
        value={search}
        onChange={setSearch}
        placeholder="Rechercher un thème..."
      />

      {/* Category chips */}
      <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
        {categories.map((cat) => (
          <button
            key={cat.id}
            onClick={() => setActiveCategory(cat.id)}
            className="shrink-0 rounded-xl px-4 py-2 text-sm font-medium transition-all duration-200 cursor-pointer"
            style={{
              background:
                activeCategory === cat.id
                  ? 'rgba(58, 170, 96, 0.15)'
                  : 'var(--bg-secondary)',
              color:
                activeCategory === cat.id
                  ? '#59b778'
                  : 'var(--text-muted)',
              border:
                activeCategory === cat.id
                  ? '1px solid rgba(58, 170, 96, 0.3)'
                  : '1px solid var(--border-subtle)',
            }}
          >
            {cat.label}
          </button>
        ))}
      </div>

      {/* Results */}
      {filteredThemes.length === 0 ? (
        <EmptyState
          icon={SearchIcon}
          title="Aucun thème trouvé"
          description="Essayez de modifier votre recherche ou vos filtres."
          actionLabel="Réinitialiser"
          onAction={() => {
            setSearch('');
            setActiveCategory('all');
          }}
        />
      ) : (
        <motion.div
          key={activeCategory + search}
          variants={containerVariants}
          initial="hidden"
          animate="visible"
          className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4"
        >
          {filteredThemes.map((theme) => {
            const itemCount = contentItems.filter(
              (c) => c.themeId === theme.id
            ).length;

            return (
              <motion.div key={theme.id} variants={itemVariants}>
                <Link href={`/explore/${theme.id}`} className="block">
                  <Card hoverable glowColor="green" className="overflow-hidden">
                    <div
                      className="h-full p-4 sm:p-5"
                      style={{ borderLeft: `3px solid ${theme.color}` }}
                    >
                      <div className="flex items-start gap-3 mb-3">
                        {/* Icon circle */}
                        <div
                          className="flex h-10 w-10 shrink-0 items-center justify-center rounded-xl text-sm font-bold"
                          style={{
                            background: `${theme.color}20`,
                            color: theme.color,
                          }}
                        >
                          {theme.title.charAt(0)}
                        </div>

                        <div className="min-w-0 flex-1">
                          <h3
                            className="text-sm font-semibold leading-snug truncate"
                            style={{ color: 'var(--text-primary)' }}
                          >
                            {theme.title}
                          </h3>
                          {theme.titleAr && (
                            <p
                              className="text-xs mt-0.5"
                              style={{
                                color: 'var(--text-muted)',
                                direction: 'rtl',
                              }}
                            >
                              {theme.titleAr}
                            </p>
                          )}
                        </div>
                      </div>

                      <p
                        className="text-xs leading-relaxed mb-3 line-clamp-2"
                        style={{ color: 'var(--text-secondary)' }}
                      >
                        {theme.description}
                      </p>

                      <div className="flex items-center justify-between gap-2">
                        <Badge variant="default" size="sm">
                          {itemCount} contenu{itemCount !== 1 ? 's' : ''}
                        </Badge>

                        {typeof theme.progress === 'number' && (
                          <div className="flex items-center gap-2 flex-1 max-w-[120px]">
                            <div
                              className="h-1.5 flex-1 rounded-full overflow-hidden"
                              style={{ background: 'rgba(255,255,255,0.08)' }}
                            >
                              <motion.div
                                initial={{ width: 0 }}
                                animate={{ width: `${theme.progress}%` }}
                                transition={{ duration: 0.8, ease: 'easeOut' }}
                                className="h-full rounded-full"
                                style={{ background: theme.color }}
                              />
                            </div>
                            <span
                              className="text-xs tabular-nums"
                              style={{ color: 'var(--text-muted)' }}
                            >
                              {theme.progress}%
                            </span>
                          </div>
                        )}
                      </div>
                    </div>
                  </Card>
                </Link>
              </motion.div>
            );
          })}
        </motion.div>
      )}
    </div>
  );
}
